// Actor that processes only validated, safely-deserialized messages
class MessageProcessorActor extends Actor with ActorLogging {

  import Messages._

  override def receive: Receive = {
    case msg: TextMessage =>
      log.info(s"Processing text message from '${msg.sender}': ${msg.content}")

    case msg: CommandMessage =>
      log.info(s"Processing command '${msg.command}' with ${msg.parameters.size} parameters")

    case msg: StatusRequest =>
      log.info(s"Processing status request: ${msg.requestId}")
      sender() ! s"""{"requestId":"${msg.requestId}","status":"ok"}"""

    case unknown =>
      log.warning(s"Received unexpected message type: ${unknown.getClass.getName}. Ignoring.")
  }
}

